import{t as e}from"./apiClient-CdSaRFMD.js";var t={getMyCareerPaths:async()=>(await e.get(`/UserCareerPath/my-career-paths`)).data,getPathsByStatus:async t=>(await e.get(`/UserCareerPath/GetCareerPaths`,{params:{careerPathStatus:t}})).data,getUserCareerPathById:async t=>(await e.get(`/UserCareerPath/${t}`)).data,enroll:async t=>(await e.post(`/UserCareerPath/enroll`,{careerPathId:t,careerPathStatus:`NotStarted`})).data,unenroll:async t=>(await e.delete(`/UserCareerPath/unenroll/${t}`)).data,checkEnrollment:async t=>(await e.get(`/UserCareerPath/is-enrolled/${t}`)).data,getRecommended:async()=>{try{return(await e.get(`/UserCareerPath/recommended`)).data}catch(e){return console.warn(`Recommended paths not available yet.`,e.response?.status),[]}}};export{t};